# 汇总并设置最终输出变量；严格复用上游已计算结果，不重新查询或重算

peak_flue_gas = float(airpoll_hangang_hanbao_peak_flue_gas_for_synthesis)
mean_flue_gas = float(airpoll_hangang_hanbao_mean_flue_gas_for_synthesis)
std_flue_gas = float(airpoll_hangang_hanbao_std_flue_gas_for_synthesis)
peak_flue_gas_offset_hours = int(airpoll_hangang_hanbao_peak_flue_gas_offset_hours_for_synthesis)

summary_lines = []
summary_lines.append("邯钢集团邯宝钢铁有限公司在2025-06-10至2025-06-12期间的小时烟气排放统计已完成。")
summary_lines.append(f"峰值烟气量：{peak_flue_gas}")
summary_lines.append(f"平均小时烟气量：{mean_flue_gas}")
summary_lines.append(f"小时烟气量总体标准差：{std_flue_gas}")
summary_lines.append(f"峰值相对2025-06-10 00:00的整小时偏移：{peak_flue_gas_offset_hours}小时")

# 高排放与不利气象重叠情况：仅做汇总和少量概述，不输出大表
try:
    hp_df = airpoll_hangang_hanbao_high_emission_periods_for_synthesis
    overlap_df = met_hangang_hanbao_high_emission_weather_overlap_hours_for_synthesis
    assess_clean = met_hangang_hanbao_high_emission_weather_assessment_clean_for_synthesis
    assess_raw = met_hangang_hanbao_high_emission_weather_assessment_for_synthesis

    if hasattr(hp_df, "shape"):
        summary_lines.append(f"识别到的高排放时段记录数：{int(hp_df.shape[0])}")
    if hasattr(overlap_df, "shape"):
        summary_lines.append(f"高排放且存在不利气象重叠的小时记录数：{int(overlap_df.shape[0])}")

    if isinstance(assess_clean, dict) and assess_clean:
        for k, v in assess_clean.items():
            if isinstance(v, (int, float, str, bool)) or v is None:
                summary_lines.append(f"清洗后气象关联指标-{k}：{v}")
            elif isinstance(v, dict):
                compact = {kk: vv for kk, vv in v.items() if isinstance(vv, (int, float, str, bool)) or vv is None}
                if compact:
                    summary_lines.append(f"清洗后气象关联指标-{k}：{compact}")
    elif isinstance(assess_raw, dict) and assess_raw:
        for k, v in assess_raw.items():
            if isinstance(v, (int, float, str, bool)) or v is None:
                summary_lines.append(f"气象关联指标-{k}：{v}")
            elif isinstance(v, dict):
                compact = {kk: vv for kk, vv in v.items() if isinstance(vv, (int, float, str, bool)) or vv is None}
                if compact:
                    summary_lines.append(f"气象关联指标-{k}：{compact}")

    if hasattr(overlap_df, "empty") and not overlap_df.empty:
        time_like_cols = [c for c in overlap_df.columns if ("time" in str(c).lower()) or ("timestamp" in str(c).lower()) or ("start" in str(c).lower()) or ("end" in str(c).lower())]
        metric_cols = [c for c in overlap_df.columns if c not in time_like_cols]
        compact_cols = (time_like_cols + metric_cols)[:6]
        small_overlap = overlap_df[compact_cols].head(5).to_string(index=False)
        summary_lines.append("高排放与不利气象重叠记录示例（最多5条）：")
        summary_lines.append(small_overlap)
    else:
        summary_lines.append("未识别到可汇总输出的高排放与不利气象重叠小时记录。")
except NameError as exc:
    summary_lines.append(f"高排放与不利气象关联汇总所需的上游变量缺失：{exc}")
except Exception as exc:
    summary_lines.append(f"高排放与不利气象关联汇总生成失败：{type(exc).__name__}: {exc}")

print("\n".join(summary_lines))
print("peak_flue_gas =", peak_flue_gas)
print("mean_flue_gas =", mean_flue_gas)
print("std_flue_gas =", std_flue_gas)
print("peak_flue_gas_offset_hours =", peak_flue_gas_offset_hours)
